choose.when:
SELECT t.categories_time, t.hour_time, ROUND(
, 1) AS energy, ROUND(AVG(IF(t.id_device_type IN (4,6), t.`value`, NULL)), 1) AS irradiance FROM (
SELECT AS time_format, AS categories_time, AS hour_time, s.dc_capacity, s.interval_energy_threshold, s.minimum_energy_value, d.id, d.id_device_type, CONVERT_TZ( dv.time, 'UTC', t.value ) AS time,
m.`value`
AS `value` FROM ${item.datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone JOIN ( SELECT AS leadTimeValid, MIN(dv.time) AS minTime, MAX(dv.time) AS maxTime,
AVG(dv.nvm_irradiance)
NULL
AS `value` FROM ${item.datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone WHERE SHA1(s.id) = #{hash_id} AND s.`status` = 1 AND d.id = #{item.id} AND d.`status` = 1 AND dv.time BETWEEN CONVERT_TZ(#{start_date}, t.value, 'UTC') AND CONVERT_TZ(#{end_date}, t.value, 'UTC') AND dv.error = 0 GROUP BY
) m ON m.minTime = dv.time AND dv.id_device = #{item.id}
) t GROUP BY t.time_format
